class EnvVarCheck
{
    void CheckFlag()
    {
        // In .NET 9+, GetEnvironmentVariable returns null for empty values on Linux.
        // Use GetEnvironmentVariables() to distinguish "not set" from "explicitly empty".
        IDictionary envVars = Environment.GetEnvironmentVariables();
        if (!envVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

